"use strict";parserFactory.register("novelfever.com",()=>new NovelFeverParser);class NovelFeverParser extends Parser{constructor(){super()}async getChapterUrls(e){let r=e.querySelector("#list-chapters");return util.hyperlinksToChapterList(r)}findContent(e){return e.querySelector("div#chapter-content")}extractTitleImpl(e){return e.querySelector("h1")}findChapterTitle(e){let r=e.querySelector("div#chapter-infomation div.text-overflow-1-lines");return null!==r?r.textContent:null}findCoverImageUrl(e){return util.getFirstImgSrc(e,"section#book-infomation")}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("div#about")]}cleanInformationNode(e){util.removeChildElementsMatchingSelector(e,"#book-review")}}